import * as React from "react"
import { useState, useEffect } from "react"
import { Link, HeadFC, PageProps } from "gatsby"
import Layout from "../components/Layout"
import { LanguageProvider } from "../context/LanguageContext"
import { Terminal, ArrowLeft } from "lucide-react"

const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789@#$%&*"

const ScrambleText: React.FC<{ text: string; delay?: number }> = ({ text, delay = 0 }) => {
  const [displayed, setDisplayed] = useState(text.split('').map(() => chars[Math.floor(Math.random() * chars.length)]).join(''))

  useEffect(() => {
    const timeout = setTimeout(() => {
      let iteration = 0
      const interval = setInterval(() => {
        setDisplayed(
          text.split('').map((char, i) => {
            if (i < iteration) return char
            return chars[Math.floor(Math.random() * chars.length)]
          }).join('')
        )
        iteration += 1 / 2
        if (iteration >= text.length) clearInterval(interval)
      }, 40)
      return () => clearInterval(interval)
    }, delay)
    return () => clearTimeout(timeout)
  }, [text, delay])

  return <span>{displayed}</span>
}

const NotFoundPage: React.FC<PageProps> = () => {
  return (
    <LanguageProvider>
      <Layout>
        <div style={{ 
          textAlign: "center", 
          padding: "120px 20px 80px",
          minHeight: "60vh",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          gap: "2rem"
        }}>
          <div style={{ 
            fontSize: "7rem", 
            fontFamily: "var(--font-mono)",
            fontWeight: 800,
            lineHeight: 1,
            background: "linear-gradient(135deg, var(--accent-primary), var(--accent-secondary))",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            backgroundClip: "text"
          }}>
            <ScrambleText text="404" />
          </div>
          <div className="glass-card" style={{ 
            padding: "1.5rem 2rem", 
            maxWidth: "480px",
            fontFamily: "var(--font-mono)",
            fontSize: "0.9rem",
            textAlign: "left",
            lineHeight: 1.8
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "1rem", color: "var(--accent-primary)" }}>
              <Terminal size={16} />
              <span style={{ fontWeight: 600 }}>tosqui@sec ~</span>
            </div>
            <p style={{ color: "var(--text-secondary)" }}>
              <span style={{ color: "var(--accent-red)" }}>Error:</span> Route not found in filesystem.
            </p>
            <p style={{ color: "var(--text-muted)", marginTop: "0.5rem" }}>
              The requested resource does not exist or has been moved.
            </p>
          </div>
          <Link 
            to="/" 
            className="btn-gradient" 
            style={{ marginTop: "1rem" }}
          >
            <ArrowLeft size={18} /> Back to Home
          </Link>
        </div>
      </Layout>
    </LanguageProvider>
  )
}

export default NotFoundPage

export const Head: HeadFC = () => <title>404 - Not Found | tosqui</title>
